import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';
import Navbar      from './components/Navbar';
import Portfolio   from './pages/Portfolio';
import Register    from './pages/Register';
import Login       from './pages/Login';
import Admin       from './pages/Admin';
import EditProfile from './pages/EditProfile';

// Only the logged-in owner can access these
function OwnerRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return (
    <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height:'100vh' }}>
      <div className="spin" />
    </div>
  );
  return user ? children : <Navigate to="/login" replace />;
}

function AppInner() {
  const { user, registered, loading } = useAuth();

  // Still checking registration status
  if (registered === null || loading) return (
    <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height:'100vh' }}>
      <div className="spin" />
    </div>
  );

  return (
    <>
      <Navbar />
      <Routes>
        {/* PUBLIC — your portfolio homepage, everyone can see it */}
        <Route path="/" element={<Portfolio />} />

        {/* REGISTER — only visible if no owner registered yet */}
        <Route path="/register" element={
          !registered ? <Register /> : <Navigate to="/login" replace />
        } />

        {/* LOGIN — redirect to admin if already logged in */}
        <Route path="/login" element={
          user ? <Navigate to="/admin" replace /> : <Login />
        } />

        {/* ADMIN — only owner can access */}
        <Route path="/admin"         element={<OwnerRoute><Admin /></OwnerRoute>} />
        <Route path="/admin/profile" element={<OwnerRoute><EditProfile /></OwnerRoute>} />

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppInner />
        <Toaster
          position="top-right"
          toastOptions={{
            duration: 3000,
            style: {
              background: '#13131e',
              color: '#f1f1f8',
              border: '1px solid rgba(255,255,255,0.1)',
              fontFamily: "'Plus Jakarta Sans', sans-serif",
              fontSize: '13px',
              borderRadius: '10px',
              boxShadow: '0 8px 32px rgba(0,0,0,0.5)',
            },
            success: { iconTheme: { primary: '#a78bfa', secondary: '#13131e' } },
            error:   { iconTheme: { primary: '#ef4444', secondary: '#13131e' } },
          }}
        />
      </BrowserRouter>
    </AuthProvider>
  );
}
